        ['produkt-haendler-nachweisakte', 'Produkte und Handel', 'start', 'Produkt-/Haendler-Nachweisakte', 'Produktunterlagen, Registrierungen und Quellen je SKU ablegen', 'Fuer Haendler, Importeure und Marken: GPSR, VerpackG/LUCID, WEEE, Batterie, BFSG, Lieferantenunterlagen und Rueckrufordner als Nachweisakte. Optional Vermittlung passender Dienstleister fuer Verpackungslizenz oder Konformitaetspruefung.', 'Onlinehaendler, Importeure, D2C-Marken, Produktmanager, Agenturen und Berater.', 'Produktakte, Quellen, Registrierungsbelege, Lieferantennachweise, Rueckruf-/Marktueberwachungsordner.', 'Keine automatische Produktbewertung und keine Produktkonformitaetsfreigabe.', 'Produktakte anfragen', '/kontakt', 'EU Product Safety', 'https://commission.europa.eu/business-economy-euro/product-safety-and-requirements/product-safety_en', 1, 1, 10],
        ['prueffristen-tracker', 'Pruef- und Betreiberfristen', 'start', 'Pruef-/Fristen-Tracker', 'Wiederkehrende Pruefungen und Nachweise an einem Ort', 'DGUV-nahe Pruefungen, Feuerloescher, Leitern, Unterweisungen, Gebaeude- und Betreiberfristen werden als Fristen und Nachweisordner verwaltet. Bei faelligen Fristen optional Angebot passender Pruefdienstleister.', 'Betriebe mit Arbeitsmitteln, Standorten, Unterweisungen, Wartungen und Pruefbelegen.', 'Fristen, Verantwortliche, Dokumente, Portalbelege, Exportordner, Status offen/faellig/erledigt.', 'Keine Entscheidung, welche Pruefung gesetzlich im Einzelfall erforderlich ist. Nutzer oder Fachpartner legen Inhalte und Fristen fest.', 'Demo anfragen', '/kontakt', 'DGUV', 'https://www.dguv.de/', 1, 1, 20],
        ['ki-verordnung-nachweisakte', 'Datenschutz und IT', 'start', 'KI-Verordnung / AI-Act Nachweisakte', 'KI-Register, Schulungsnachweise und Betreiberpflichten dokumentieren', 'EU-KI-Verordnung: KI-Kompetenz-Nachweise (seit 02/2025) und Betreiberpflichten (ab 08/2026) als Register, Aufgaben- und Nachweisakte fuehren. Neue Pflicht ohne etablierten Wettbewerber.', 'Unternehmen, die KI-Systeme einsetzen: Marketing, HR, Support, Produktteams, Agenturen.', 'KI-Register, Anwendungsfaelle, Risikoklassen, Schulungsnachweise, Logs, Verantwortliche, Export.', 'Keine rechtliche Einstufung der Risikoklasse und keine Konformitaetsfreigabe durch die Plattform.', 'AI-Act-Modul vormerken', '/kontakt', 'EU-KI-Verordnung (VO 2024/1689)', 'https://eur-lex.europa.eu/eli/reg/2024/1689/oj', 1, 1, 30],
        ['beraterzugang', 'Berater', 'start', 'Kanzlei- und Berater-Cockpit', 'Mandanten-Pflichten und Nachweise ueber alle Mandate im Blick', 'Steuerberater, Lohnbueros, Sifa, Pruefer und Fachberater sehen offene Nachweise je Mandant, fordern Belege an und exportieren fertige Nachweisordner. Das Cockpit ist der Multiplikator: die Kanzlei bucht, die Mandanten liefern.', 'Kanzleien, Lohnbueros, Sicherheitsfachkraefte, Pruefer und Fachberater mit vielen Mandanten.', 'Mandantenliste, offene Aufgaben je Mandant, Beleganforderung, Fristen, Export, Notizen, Rollen.', 'Die fachliche Bewertung trifft der Berater; die Plattform organisiert Nachweise und Fristen.', 'Kanzlei-Cockpit anfragen', '/kontakt', 'DSGVO Art. 28 (Auftragsverarbeitung)', 'https://dsgvo-gesetz.de/art-28-dsgvo/', 1, 1, 40],
        ['steuer-register-fristen', 'Steuern und Register', 'next', 'Steuer-/Registerfristen', 'Offenlegung, E-Rechnung und GoBD-Belege fuer die Kanzlei', 'Jahresabschluss- und Offenlegungsakte, E-Rechnung (Empfangspflicht seit 2025, Ausstellungspflicht gestaffelt bis 2028), TSE/GoBD-Belege und Portalquittungen als strukturierter Arbeitsordner.', 'GmbH, UG, Steuerberater, Lohnbueros, Buchhaltung und Finance-Teams.', 'Fristen, Belege, Einreichungsquittungen, Steuerberaterexport, Jahresordner.', 'Keine Steuerberatung, keine Abschlussfreigabe und keine automatische Einreichung.', 'Startpaket besprechen', '/kontakt', 'Unternehmensregister', 'https://www.unternehmensregister.de/', 0, 1, 50],
